	// We use BFS to compute the popcount-depth for all numbers up to n

	// Initialize a map to store the popcount-depth for each number
	popcountDepth := make(map[int64]int64)

	// Queue for BFS
	queue := []int64{1}
	popcountDepth[1] = 0

	// Process the queue
	for len(queue) > 0 {
		current := queue[0]
		queue = queue[1:]

		currentDepth := popcountDepth[current]

		// If currentDepth + 1 is greater than k, we can skip further processing
		// because we only care about numbers with popcount-depth exactly k
		if currentDepth+1 > k {
			continue
		}

		// Compute the popcount of current
		popcount := bits.OnesCount64(current)

		// If popcount is 1, then current's popcount-depth is currentDepth + 1
		if popcount == 1 {
			popcountDepth[current] = currentDepth + 1
			continue
		}

		// Otherwise, add the popcount to the queue
		queue = append(queue, int64(popcount))
